  useEffect(() => {
    return () => {
      clearInterval(timerRef.current);
      if (sessionRole === "viewer" && liveSession?.hostId) {
        socket?.emit("leaveLive", { hostId: liveSession.hostId });
      }
      destroyHostPeers();
      destroyViewerPeer();
      stopCamera();
      stopRemoteStream();
